// Unit test — test in isolation
function calculateTotal(items) {
  return items.reduce((sum, item) => sum + item.price * item.qty, 0);
}

test('calculates total correctly', () => {
  const items = [
    { price: 10, qty: 2 },
    { price: 5, qty: 3 }
  ];
  expect(calculateTotal(items)).toBe(35);
});

test('returns 0 for empty cart', () => {
  expect(calculateTotal([])).toBe(0);
});

// HARD to test — hardcoded dependency
function getUser(id) {
  const db = new Database('prod');
  return db.query('SELECT * FROM users WHERE id = $1', [id]);
}

// EASY to test — injected dependency
function getUser(id, db) {
  return db.query('SELECT * FROM users WHERE id = $1', [id]);
}

// Test with mock
test('getUser queries database', async () => {
  const mockDb = { query: jest.fn().mockResolvedValue({ name: 'Alice' }) };
  const user = await getUser(1, mockDb);
  expect(mockDb.query).toHaveBeenCalledWith(
    'SELECT * FROM users WHERE id = $1', [1]
  );
});
